        color="red"
    )

    # Test placing the shape
    if grid.is_valid_move(example_shape, 3, 2):
        grid.place_shape(example_shape, 3, 2)
        print("Shape placed successfully!")
    else:
        print("Cannot place shape at the specified location.")
